import{c as d,a0 as c,U as s,j as r,g as o,n,o as t,m as l}from"./chunks/framework.Dvkoa_vi.js";const S=JSON.parse('{"title":"Respuestas — Sesión 5: Servicios y acceso a Oracle","description":"Solucionario razonado del test de 21 preguntas de la Sesión 5.","frontmatter":{"title":"Respuestas — Sesión 5: Servicios y acceso a Oracle","description":"Solucionario razonado del test de 21 preguntas de la Sesión 5.","outline":[2,2],"search":false},"headers":[],"relativePath":"02-dotnet/test/sesion-05/respuestas.md","filePath":"02-dotnet/test/sesion-05/respuestas.md"}'),i={name:"02-dotnet/test/sesion-05/respuestas.md"};function u(p,e,m,g,v,b){const a=c("CopyOrDownloadAsMarkdownButtons");return s(),r("div",null,[e[0]||(e[0]=o("div",{style:{display:"none"},hidden:"true","aria-hidden":"true"},"Are you an LLM? You can read better optimized documentation at /curso-normalizacion/02-dotnet\\test\\sesion-05\\respuestas.md for this page in Markdown format",-1)),e[1]||(e[1]=o("h1",{id:"respuestas-—-test-sesion-5-servicios-y-acceso-a-oracle",tabindex:"-1"},[n("Respuestas — Test Sesión 5: Servicios y acceso a Oracle "),o("a",{class:"header-anchor",href:"#respuestas-—-test-sesion-5-servicios-y-acceso-a-oracle","aria-label":"Permalink to “Respuestas — Test Sesión 5: Servicios y acceso a Oracle”"},"​")],-1)),t(a),e[2]||(e[2]=l("<ol><li><p><strong>b)</strong> Error de mapeo: la librería buscará una columna <code>TIENE_CONTENIDO</code> que no existe. <code>ClaseOracleBD3</code> intenta mapear TODAS las propiedades públicas del modelo a columnas Oracle. Sin <code>[IgnorarMapeo]</code>, buscará una columna para <code>TieneContenido</code> y fallará al no encontrarla.</p></li><li><p><strong>c)</strong> <code>[IgnorarMapeo]</code>. Es el atributo propio de <code>ClaseOracleBD3</code> que indica que una propiedad no corresponde a ninguna columna de la base de datos. <code>[JsonIgnore]</code> es para serialización JSON, <code>[NotMapped]</code> es de Entity Framework, y <code>[Computed]</code> no existe en este contexto.</p></li><li><p><strong>b)</strong> <code>ClaseReserva.cs</code>, <code>ClaseReservas.cs</code>, <code>IClaseReservas.cs</code>. La convención UA usa prefijo <code>Clase</code> + singular para el DTO, <code>Clase</code> + plural para el servicio, e <code>I</code> + <code>Clase</code> + plural para la interfaz.</p></li><li><p><strong>b)</strong> <code>bd.Command.Parameters.Clear();</code>. Después de cada <code>bd.Ejecutar()</code>, hay que limpiar los parámetros para evitar que se acumulen entre llamadas sucesivas al paquete. Es un patrón obligatorio en <code>ClaseOracleBD3</code>.</p></li><li><p><strong>b)</strong> Para parámetros que envían un valor (ej: <code>Id=0</code> para crear) y reciben otro (ej: <code>Id</code> generado). <code>InputOutput</code> se usa típicamente con el parámetro <code>p_id</code> que vale 0 para creación (Oracle genera el <code>ID</code> desde una secuencia) o un valor existente para modificación.</p></li><li><p><strong>b)</strong> Se convierte automáticamente a <code>true</code>. <code>ClaseOracleBD3</code> convierte automáticamente <code>&#39;S&#39;</code>, <code>&#39;Y&#39;</code>, <code>&#39;1&#39;</code>, <code>&#39;SI&#39;</code> a <code>true</code> y cualquier otro valor a <code>false</code> cuando la propiedad destino es <code>bool</code>.</p></li><li><p><strong>b)</strong> <code>NOMBRE_CA</code> y <code>DESCRIPCION_CA</code>. Cuando se pasa <code>idioma: &quot;CA&quot;</code>, <code>ClaseOracleBD3</code> añade el sufijo <code>_CA</code> a las propiedades de tipo <code>string</code> que tengan columnas multiidioma, buscando <code>NOMBRE_CA</code> y <code>DESCRIPCION_CA</code>.</p></li><li><p><strong>b)</strong> <code>[Columna]</code>, luego nombre exacto (case-insensitive), luego PascalCase → SNAKE_CASE, luego sufijo idioma. La prioridad más alta es el atributo <code>[Columna]</code>, seguido del nombre exacto de la propiedad, luego la conversión automática PascalCase → SNAKE_CASE, y finalmente la búsqueda con sufijo de idioma.</p></li><li><p><strong>c)</strong> No tiene permisos directos sobre las tablas — usa vistas <code>VRES_*</code> para leer y paquetes <code>PKG_RES_*</code> para escribir. El usuario web solo tiene <code>SELECT</code> sobre vistas (<code>VRES_*</code>) y <code>EXECUTE</code> sobre paquetes (<code>PKG_RES_*</code>). No puede hacer <code>INSERT</code>, <code>UPDATE</code> ni <code>DELETE</code> directamente en las tablas <code>TRES_*</code>.</p></li><li><p><strong>b)</strong> <code>ObtenerTodosMap</code> devuelve <code>IEnumerable&lt;T&gt;?</code> y <code>ObtenerPrimeroMap</code> devuelve <code>T?</code>. El primero retorna una colección (que puede ser null), el segundo retorna un único objeto o null si no hay resultados.</p></li><li><p><strong>c)</strong> <code>builder.Services.AddScoped&lt;IClaseUnidades, ClaseUnidades&gt;();</code>. Los servicios que dependen de <code>ClaseOracleBd</code> (que es <code>Scoped</code>) deben registrarse como <code>Scoped</code>. <code>Singleton</code> causaría captive dependency con la conexión a BD, y sin interfaz se pierde la capacidad de fakear en tests.</p></li><li><p><strong>b)</strong> <code>Result</code> con <code>IsSuccess = false</code> y <code>Error.Type = ErrorType.NotFound</code>. El operador ternario comprueba si <code>unidad is null</code> y en ese caso retorna <code>Result&lt;ClaseUnidad&gt;.NotFound(...)</code>, que tiene <code>IsSuccess = false</code> y el error tipado como <code>NotFound</code>. <code>HandleResult</code> lo convertirá en un <code>404 Not Found</code> con <code>ProblemDetails</code>.</p></li><li><p><strong>c)</strong> 200 OK con el valor serializado. Cuando <code>result.IsSuccess</code> es <code>true</code>, <code>HandleResult</code> ejecuta <code>return Ok(result.Value)</code>, que produce un HTTP 200 con el valor serializado a JSON.</p></li><li><p><strong>d)</strong> El contrato solo define dos códigos de error: 400 y 500 → FALSA. El contrato UA define tres códigos de error: 400 para <code>Validation</code>, 404 para <code>NotFound</code> y 500 para <code>Failure</code>. La afirmación c) es VERDADERA: cuando un recurso no se encuentra, el servicio retorna <code>Result.NotFound(...)</code> y <code>HandleResult</code> lo convierte en 404. (El detalle completo del mapeo <code>ErrorType</code> → HTTP se ve en la sesión 16.)</p></li><li><p><strong>b)</strong> Por seguridad: el <code>CodPer</code> debe venir del servidor (token JWT del usuario autenticado), nunca del cliente. <code>CodPer</code> se lee del JWT en <code>ControladorBase</code>. Aceptar este valor del body sería una vulnerabilidad: un usuario malicioso podría crear recursos a nombre de otra persona.</p></li><li><p><strong>c)</strong> <code>void</code>. <code>EjecutarParams</code> en su versión síncrona no devuelve valor. Se usa para ejecutar procedimientos almacenados que no retornan conjuntos de datos. Los valores de salida (<code>OUT</code> / <code>InputOutput</code>) se recuperan vía <code>bd.Command.Parameters[&quot;p_xxx&quot;].Value</code>.</p></li><li><p><strong>b)</strong> <code>bd.ObtenerTodosMap&lt;T&gt;(sql, new { activo = &quot;S&quot;, sala = &quot;A&quot; })</code>. Los parámetros se pasan como un objeto anónimo donde cada propiedad corresponde a un parámetro SQL nombrado (<code>:activo</code>, <code>:sala</code>).</p></li><li><p><strong>b)</strong> <code>Result.IsSuccess</code>. La propiedad <code>IsSuccess</code> de <code>Result&lt;T&gt;</code> indica si la operación fue exitosa (<code>true</code>) o si hubo un error (<code>false</code>). Es una propiedad de solo lectura establecida en el constructor.</p></li><li><p><strong>c)</strong> Necesita <code>[Columna(&quot;COD_USR&quot;)]</code> porque la conversión PascalCase → SNAKE_CASE no funciona con abreviaturas. <code>CodUsr</code> se convertiría a <code>COD_USR</code> solo si &quot;Usr&quot; se descompone correctamente, pero las abreviaturas pueden no seguir el patrón esperado. Cuando los nombres de columna son abreviaturas, <code>[Columna]</code> es necesario.</p></li><li><p><strong>b)</strong> Porque el parámetro de entrada del paquete Oracle espera un <code>VARCHAR2</code>, no un booleano (Oracle no tiene <code>BOOLEAN</code> nativo en la API SQL). Los paquetes PL/SQL usan <code>VARCHAR2</code> con valores <code>&#39;S&#39;</code>/<code>&#39;N&#39;</code>, por lo que hay que convertir el <code>bool</code> de C# al string equivalente al pasar el parámetro.</p></li><li><p><strong>c)</strong> En el servicio (<code>ReservasServicio.cs</code>). En la arquitectura de capas de la UA, toda la lógica SQL y de acceso a datos va en el servicio. Los controladores solo orquestan (reciben la petición, llaman al servicio, devuelven el resultado con <code>HandleResult</code>). Los DTOs son solo estructuras de datos.</p></li></ol>",1))])}const E=d(i,[["render",u]]);export{S as __pageData,E as default};
